# Explorer packet solve S51-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'pii_in_trace', 'case_id', 'spans', 'versions', 'trace_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["trace_id"] or record["pii_in_trace"])) else 'REDACT_AND_QUARANTINE_TRACE'

